import { GoogleGenAI } from "@google/genai";

export type ToolType = 'general' | 'ancient' | 'essay' | 'lesson' | 'reading' | 'poetry';

const TOOL_PROMPTS: Record<ToolType, string> = {
  general: "你是一位资深的语文教学专家。请为老师提供专业的建议、灵感或资源。",
  ancient: "你是一位古典文献学专家。请对输入的文言文进行精准翻译（字对字与意译）、重点实词解析、虚词用法说明，并提取文中的文化常识与艺术特色。",
  poetry: "你是一位精通中国古典诗词的文学评论家与教育专家。请对输入的诗词进行深度鉴赏，重点分析：1. 意境与意象；2. 修辞手法与炼字艺术；3. 作者生平背景及创作时节；4. 核心情感与哲学内涵的深度表达。",
  essay: "你是一位作文阅卷组组长。请从‘语言表达、立意深度、结构逻辑、素材运用’四个维度批改作文。先给出综合评分（百分制），然后列出3个闪光点和2个改进建议，最后提供一段润色后的范文片段。",
  lesson: "你是一位特级语文教师。请根据输入的课文内容或题目，编写一份符合现代教育要求的教案。教案须包含：1. 教学目标（含核心素养）；2. 教学重难点；3. 教学步骤（导入、初读、研读、总结）；4. 课后作业设计。",
  reading: "你是一位阅读推广人。请针对特定书籍或文章，梳理人物关系图谱、核心情节脉络，并设计3个具有思维挑战性的深度探究问题。"
};

export class GeminiService {
  async generateTeachingResource(prompt: string, type: ToolType = 'general', isPro: boolean = false) {
    try {
      const modelName = isPro ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
      const systemInst = TOOL_PROMPTS[type] + " 请使用清晰的 Markdown 格式输出。";

      if (isPro) {
        // 专家模式：必须在调用前创建实例以确保获取最新的 API_KEY
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: modelName,
          contents: [{ parts: [{ text: prompt }] }],
          config: { 
            systemInstruction: systemInst,
            temperature: 0.7 
          },
        });

        if (!response.text) {
           throw new Error("模型未返回有效内容");
        }
        return response.text;
      } else {
        // 普通模式：通过内置代理
        const proxyUrl = `/api/v1beta/models/${modelName}:generateContent`;
        const response = await fetch(proxyUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text: prompt }] }],
            system_instruction: { parts: [{ text: systemInst }] },
            generationConfig: { 
              temperature: 0.7,
              maxOutputTokens: 2048
            }
          })
        });

        const data = await response.json();
        if (!response.ok) {
          if (data.error?.message?.includes("not found")) {
            return "ERROR_KEY_INVALID";
          }
          throw new Error(data.error?.message || '请求失败');
        }

        return data.candidates?.[0]?.content?.parts?.[0]?.text || "语枢目前无法生成内容，请稍后再试。";
      }
    } catch (error: any) {
      console.error("Gemini Service Error:", error);
      // 捕获 Key 相关错误
      if (error.message?.includes("entity was not found") || error.message?.includes("API_KEY_INVALID") || error.status === 404) {
        return "ERROR_KEY_INVALID";
      }
      return "语枢智能服务暂时无法处理您的请求，可能是系统繁忙。建议刷新页面或稍后再试。";
    }
  }
}

export const gemini = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Loader2, Scroll, PenTool, BookOpen, Library, Copy, Check, Feather, Zap, ShieldCheck, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { gemini, ToolType } from '../services/geminiService';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  type?: ToolType;
}

const TOOLS = [
  { id: 'ancient', label: '文言文解析', icon: <Scroll className="w-4 h-4" />, color: 'text-orange-400' },
  { id: 'poetry', label: '古诗词鉴赏', icon: <Feather className="w-4 h-4" />, color: 'text-yellow-400' },
  { id: 'essay', label: '作文批改', icon: <PenTool className="w-4 h-4" />, color: 'text-pink-400' },
  { id: 'lesson', label: '智能教案', icon: <Library className="w-4 h-4" />, color: 'text-blue-400' },
  { id: 'reading', label: '名著导读', icon: <BookOpen className="w-4 h-4" />, color: 'text-purple-400' },
];

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

export const AIPortal: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: '欢迎来到语枢智慧工作台。请选择工具或直接输入需求。本演示版共享 API 额度，如遇卡顿建议开启【专家模式】使用私有资源。' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolType>('general');
  const [isExpertMode, setIsExpertMode] = useState(false);
  const [copied, setCopied] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleExpertMode = async () => {
    if (typeof window.aistudio === 'undefined') {
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: '💡 专家模式说明：私有 Key 接入目前仅支持在 AI Studio 环境或配置了 API_KEY 环境变量的服务器上运行。' 
      }]);
      return;
    }

    if (!isExpertMode) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await window.aistudio.openSelectKey();
        }
        // 假设选择成功（根据规范，触发 openSelectKey 后视为成功以避免竞态）
        setIsExpertMode(true);
        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: '✨ 专家模式激活！已接入您的私有付费 Key，系统将启用 Gemini 3 Pro 旗舰模型为您提供深度解析。' 
        }]);
      } catch (e) {
        console.error("Key selection failed", e);
      }
    } else {
      setIsExpertMode(false);
      setMessages(prev => [...prev, { role: 'assistant', content: '已切回普通模式（共享额度）。' }]);
    }
  };

  const handleSend = async (overridePrompt?: string, forceType?: ToolType) => {
    const textToSend = overridePrompt || input;
    const typeToUse = forceType || activeTool;

    if (!textToSend.trim() || isLoading) return;

    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: textToSend, type: typeToUse }]);
    setIsLoading(true);

    const response = await gemini.generateTeachingResource(textToSend, typeToUse, isExpertMode);

    if (response === "ERROR_KEY_INVALID") {
      setIsExpertMode(false);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: '⚠️ 专家模式凭证异常：您的 API Key 可能已过期或余额不足。请在弹出的对话框中重新关联一个有效的付费项目 Key。' 
      }]);

      if (typeof window.aistudio !== 'undefined') {
        try {
          await window.aistudio.openSelectKey();
          setIsExpertMode(true);
        } catch (e) {}
      }
    } else {
      setMessages(prev => [...prev, { role: 'assistant', content: response || "生成资源时遇到一点小麻烦，请稍后重试。" }]);
    }
    setIsLoading(false);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <section id="experience" className="py-12 md:py-24 px-4 md:px-6 relative">
      <div className="max-w-5xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 md:mb-12 gap-6">
          <div className="text-left">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 text-emerald-400 text-[10px] md:text-xs font-bold uppercase tracking-wider mb-4 border border-emerald-500/20">
              Intelligent Workspace
            </div>
            <h2 className="text-2xl md:text-5xl font-bold">语枢 <span className="text-emerald-500">智慧工作台</span></h2>
          </div>

          <div className="flex flex-col items-end gap-2">
            <button 
              onClick={toggleExpertMode}
              className={`flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl border transition-all text-xs md:text-sm font-bold w-full md:w-auto ${
                isExpertMode 
                ? 'bg-purple-600/20 border-purple-500 text-purple-400 shadow-[0_0_20px_rgba(168,85,247,0.2)]' 
                : 'bg-white/5 border-white/10 text-white/40 hover:text-white'
              }`}
            >
              {isExpertMode ? <ShieldCheck className="w-4 h-4" /> : <Zap className="w-4 h-4" />}
              <span>{isExpertMode ? '专家模式运行中' : '切换专家模式 (私有 Key)'}</span>
            </button>
            {isExpertMode && (
              <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[10px] text-purple-400/60 hover:text-purple-400 underline transition-colors">
                结算账户文档说明
              </a>
            )}
          </div>
        </div>

        <div className="flex flex-wrap justify-start gap-2 md:gap-3 mb-8">
          {TOOLS.map((tool) => (
            <button
              key={tool.id}
              onClick={() => setActiveTool(tool.id as ToolType)}
              className={`flex items-center gap-2 px-3 py-2 md:px-4 md:py-2 rounded-xl border transition-all shrink-0 ${
                activeTool === tool.id 
                ? 'bg-emerald-600 border-emerald-500 text-white shadow-lg shadow-emerald-600/20' 
                : 'bg-white/5 border-white/10 text-white/60 hover:bg-white/10'
              }`}
            >
              <span className={activeTool === tool.id ? 'text-white' : tool.color}>{tool.icon}</span>
              <span className="text-[12px] md:text-sm font-medium">{tool.label}</span>
            </button>
          ))}
        </div>

        <div className="glass rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border border-white/10 shadow-2xl flex flex-col h-[70vh] md:h-[650px] relative">
          <div className="p-3 md:p-4 border-b border-white/5 bg-white/5 flex items-center justify-between">
            <div className="flex items-center gap-2 md:gap-3">
              <div className={`w-7 h-7 md:w-8 md:h-8 rounded-full flex items-center justify-center transition-colors ${isExpertMode ? 'bg-purple-600' : 'bg-emerald-600'}`}>
                {isExpertMode ? <Zap className="w-3 h-3 md:w-4 md:h-4 text-white" /> : <Sparkles className="w-3 h-3 md:w-4 md:h-4 text-white" />}
              </div>
              <div className="flex flex-col">
                <span className="font-semibold text-xs md:text-sm">语枢助手 {isExpertMode && <span className="text-[8px] md:text-[10px] bg-purple-500/20 text-purple-400 px-1 py-0.5 rounded ml-1 font-bold tracking-tighter">GEMINI 3 PRO</span>}</span>
                <span className="text-[8px] md:text-[10px] text-white/40">当前工具：{TOOLS.find(t => t.id === activeTool)?.label || '通用模式'}</span>
              </div>
            </div>
            <button 
              onClick={() => setMessages([{ role: 'assistant', content: '工作台已重置。' }])}
              className="text-[10px] text-white/30 hover:text-white px-2 py-1 flex items-center gap-1"
            >
              清空上下文
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth bg-black/20">
            <AnimatePresence>
              {messages.map((msg, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`flex gap-3 md:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
                >
                  <div className={`w-7 h-7 md:w-8 md:h-8 rounded-full flex items-center justify-center shrink-0 mt-1 ${
                    msg.role === 'user' ? 'bg-emerald-700' : 'bg-white/10'
                  }`}>
                    {msg.role === 'user' ? <User className="w-3 h-3 md:w-4 md:h-4" /> : <Bot className="w-3 h-3 md:w-4 md:h-4" />}
                  </div>
                  <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'} max-w-[85%] md:max-w-[80%]`}>
                    <div className={`p-4 md:p-5 rounded-2xl text-xs md:text-sm leading-relaxed relative group ${
                      msg.role === 'user' ? 'bg-emerald-700 text-white rounded-tr-none' : 'bg-white/5 border border-white/10 text-white/90 prose prose-invert max-w-none rounded-tl-none'
                    }`}>
                      <div className="whitespace-pre-wrap font-sans">
                        {msg.content}
                      </div>

                      {msg.role === 'assistant' && i > 0 && (
                        <button 
                          onClick={() => handleCopy(msg.content)}
                          className="absolute top-2 right-2 p-1.5 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          {copied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                        </button>
                      )}
                    </div>
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex gap-4">
                  <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center shrink-0">
                    <Bot className="w-4 h-4" />
                  </div>
                  <div className="p-4 md:p-5 rounded-2xl bg-white/5 border border-white/10 flex items-center gap-3">
                    <Loader2 className="w-3 h-3 md:w-4 md:h-4 animate-spin text-emerald-400" />
                    <span className="text-[10px] md:text-xs text-white/40 tracking-widest">语枢正在智能构建教学资源...</span>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <div className="p-4 md:p-6 border-t border-white/5 bg-white/[0.03]">
            <div className="flex flex-col gap-3">
              <div className="relative">
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey && window.innerWidth > 768) {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                  rows={2}
                  placeholder="在此输入您的备课需求或文本片段..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl md:rounded-2xl px-4 py-3 md:px-5 md:py-4 text-xs md:text-sm focus:outline-none focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 transition-all placeholder:text-white/20 resize-none min-h-[70px]"
                />
                <button 
                  onClick={() => handleSend()}
                  disabled={!input.trim() || isLoading}
                  className="absolute right-2 bottom-2 md:right-3 md:bottom-3 p-2.5 bg-emerald-600 text-white rounded-lg md:rounded-xl hover:bg-emerald-500 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-emerald-600/40"
                >
                  <Send className="w-4 h-4 md:w-5 md:h-5" />
                </button>
              </div>
              <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-2 px-1">
                <p className="text-[9px] md:text-[11px] text-white/20">
                  语枢 AI 可能会产生误差，请结合教材进行人工核校。
                </p>
                {isExpertMode && (
                  <span className="text-[9px] md:text-[10px] text-purple-400 font-bold flex items-center gap-1">
                    <Zap className="w-2.5 h-2.5" /> 专家通道已连接
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};
